package pe.org.camaracomercioica.protestos.service;
import org.junit.jupiter.api.Test; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension; import org.springframework.data.domain.*; import pe.org.camaracomercioica.protestos.model.*; import pe.org.camaracomercioica.protestos.repository.*; import java.util.*; import static org.assertj.core.api.Assertions.assertThat; import static org.mockito.ArgumentMatchers.*; import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class) class DashboardServiceTest {@Mock SolicitudRepository solicitudes;@Mock UsuarioRepository usuarios;@Mock EntidadFinancieraRepository entidades;
  @Test void limitaResumenDeEntidadASuPropiaEntidad(){var rol=new Rol();rol.setNombre("BANK_ANALYST");var entidad=new EntidadFinanciera();entidad.setId(7L);entidad.setRazonSocial("Entidad");var u=new Usuario();u.setRol(rol);u.setEntidad(entidad);when(usuarios.findByEmailIgnoreCase("entidad@test.local")).thenReturn(Optional.of(u));when(solicitudes.countByEstadoAndEntidadId(any(EstadoSolicitud.class),eq(7L))).thenAnswer(i->i.getArgument(0)==EstadoSolicitud.REGISTRADA?2L:i.getArgument(0)==EstadoSolicitud.APROBADA_ENTIDAD?1L:0L);var reciente=new Solicitud();reciente.setId(1L);reciente.setCodigo("SOL-1");reciente.setEntidad(entidad);reciente.setEstado(EstadoSolicitud.REGISTRADA);when(solicitudes.findByEntidadId(eq(7L),any(Pageable.class))).thenReturn(new PageImpl<>(List.of(reciente)));when(entidades.countByActivoTrue()).thenReturn(3L);var result=new DashboardService(solicitudes,usuarios,entidades).resumen("entidad@test.local");assertThat(result.total()).isEqualTo(3);assertThat(result.pendientes()).isEqualTo(2);assertThat(result.aprobadas()).isEqualTo(1);assertThat(result.entidadesActivas()).isEqualTo(3);assertThat(result.solicitudesRecientes()).hasSize(1);verify(solicitudes,never()).countByEstado(any());}
}
